import React from "react";
import { FaBriefcase, FaUniversity, FaCloud } from "react-icons/fa";

const experienceData = [
  {
    title: "Certified SAFe® 6 Product Owner/Product Manager",
    company: "Scaled Agile",
    date: "2024",
    icon: <FaUniversity />, 
    type: "cert",
  },
  {
    title: "Senior Product Manager",
    company: "EY",
    date: "2022-Present",
    icon: <FaBriefcase />,
    type: "job",
  },
  {
    title: "Certified Scrum Product Owner (CSPO)",
    company: "Scrum Alliance",
    date: "2022",
    icon: <FaUniversity />,
    type: "cert",
  },
  {
    title: "Senior Product Manager",
    company: "J.P. Morgan",
    date: "2021-2022",
    icon: <FaBriefcase />,
    type: "job",
  },
  {
    title: "Microsoft Certified: Azure Fundamentals",
    company: "Azure",
    date: "2021",
    icon: <FaCloud />,
    type: "cert",
  },
  {
    title: "Senior Product Manager",
    company: "ExxonMobil",
    date: "2014-2021",
    icon: <FaBriefcase />,
    type: "job",
  },
  {
    title: "PMI Agile Certified Practitioner (PMIACP)",
    company: "PMI",
    date: "2019",
    icon: <FaUniversity />,
    type: "cert",
  },
  {
    title: "Senior Product Owner",
    company: "ExxonMobil",
    date: "2013-2014",
    icon: <FaBriefcase />,
    type: "job",
  },
  {
    title: "Senior Scrum Master",
    company: "ExxonMobil",
    date: "2008-2013",
    icon: <FaBriefcase />,
    type: "job",
  },
  {
    title: "Supervisor",
    company: "IBM",
    date: "2001-2008",
    icon: <FaBriefcase />,
    type: "job",
  },
  {
    title: "Master of Systems Engineering",
    company: "Universidad Tecnologica Nacional (UTN)",
    date: "2001-2006",
    icon: <FaUniversity />,
    type: "edu",
  }
];

const ExperienceTimeline = () => {
  return (
    <div className="max-w-6xl mx-auto p-4">
      <div className="relative">
        <div className="absolute left-1/2 transform -translate-x-1/2 h-full w-1 bg-gray-300"></div>
        {[...experienceData]
          .sort((a, b) => {
            const getDateValue = (dateStr) => {
              const match = dateStr.match(/\\d{4}/g);
              if (!match) return 0;
              const last = match[match.length - 1];
              return parseInt(last);
            };
            return getDateValue(b.date) - getDateValue(a.date);
          })
          .map((item, index) => {
            const isLeft = index % 2 === 0;
            return (
              <div key={index} className="w-full flex justify-between items-center mb-10">
                <div className={`w-[45%] ${isLeft ? "order-1" : "order-3"} flex justify-${isLeft ? "end" : "start"}`}>
                  <div
                    className={`px-3 py-2 rounded-lg shadow-md relative z-10 text-sm ${
                      item.type === "job"
                        ? "bg-gradient-to-r from-black via-gray-800 to-white text-white"
                        : "bg-gradient-to-r from-blue-600 via-blue-300 to-white text-black"
                    }`}
                  >
                    <p className="text-xs text-gray-200 italic mb-1 text-center">{item.date}</p>
                    <h3 className="text-base font-semibold leading-tight text-center">{item.title}</h3>
                    <p className="text-xs text-center">{item.company}</p>
                  </div>
                </div>
                <div className="z-20 flex items-center order-2 bg-white shadow-xl w-7 h-7 rounded-full border-2 border-gray-400 justify-center -mx-2">
                  {item.icon}
                </div>
                <div className="w-[45%] order-1"></div>
              </div>
            );
          })}
      </div>
    </div>
  );
};
export default ExperienceTimeline;
